import React, { useEffect, useState } from 'react';
import './App.css';
import CredencialesUsuario from './componentes/credenciales'; // Verifica si es .js o .jsx
import Prueba from './pages/prueba';
import { Routes, Route } from 'react-router-dom';

// IMPORTACIONES CON TU NUEVA ESTRUCTURA
import Sidebar from './componentes/componentes-de-layout-administrador/Sidebar';
import Dashboard from './componentes/componentes-de-layout-administrador/Dashboard'; // Este lo crearemos o usaremos como contenedor
import FilterBar from './componentes/componentes-de-layout-administrador/FilterBar';
import RankingTable from './componentes/componentes-de-layout-administrador/RankingTable';
// Nota: Si vas a usar un Modal, impórtalo también aquí

function App() {
  const [data, setData] = useState([]);
  const [examenActivo, setExamenActivo] = useState(false);

  // Estados para el panel de administración
  const [filterGrade, setFilterGrade] = useState(null);
  const [editGrade, setEditGrade] = useState(null);

  useEffect(() => {
    fetch('http://localhost:8081/usuarios')
      .then(res => res.json())
      .then(data => setData(data))
      .catch(err => console.log(err));
  }, []);

  return (
    <div className="App">
      <Routes>
        {/* RUTA DE REGISTRO */}
        <Route path="/" element={
          <div className="ventana-de-registro">
            <div className="lado-derecho-registro">
              <CredencialesUsuario alComenzar={() => setExamenActivo(true)} />
            </div>
            <div className="lado-izquierdo-registro">
              <p className="estilo-de-texto-de-formulario-registro">¡Bienvenidos!</p>
              <p className="estilo-de-texto-de-formulario-registro">Nos alegra muchísimo que estés aquí...</p>
            </div>
          </div>
        } />

        {/* RUTA DE LA PRUEBA */}
        <Route path="/prueba" element={<Prueba cronometroActivo={examenActivo} />} />

        {/* NUEVA RUTA: PANEL DE ADMINISTRACIÓN */}
        <Route path="/admin" element={
          <div className="admin-layout" style={{ display: 'flex' }}>
            <Sidebar onSelectGrade={setEditGrade} />
            
            <div className="admin-main-content" style={{ flex: 1 }}>
              <h1>Resultados Generales</h1>
              <FilterBar activeFilter={filterGrade} onFilterChange={setFilterGrade} />
              
              {/* Filtramos la data antes de pasarla a la tabla */}
              <RankingTable 
                data={data.filter(u => filterGrade ? u.grado === filterGrade : true)} 
              />
            </div>

            {/* Aquí podrías llamar a tu componente de formulario de preguntas si editGrade tiene valor */}
          </div>
        } />
      </Routes>
    </div>
  );
}

export default App;
